rss.channel:
{{ site:name }}{{ if category_title }} — {{ category_title }}{{ /if }}
{{ config:app.url }}
{{ site_settings:site_description }}
{{ site:short_locale }}

{{ now format="D, d M Y H:i:s O" }}

{{# Per-category feed — feed_category is injected via the dynamic route in routes/web.php #}}
{{ if feed_category }}
    {{ collection:articles :taxonomy:categories="feed_category" sort="date:desc" limit="20" }}


            {{ title }}
            {{ permalink }}
            {{ permalink }}
            {{ date format="D, d M Y H:i:s O" }}
            {{ categories }}{{ title }}{{ /categories }}
            {{ if dek }}{{ dek }}{{ /if }}

    {{ /collection:articles }}
{{# Global feed — all articles across all categories, most recent 20 #}}
{{ else }}
    {{ collection:articles sort="date:desc" limit="20" }}


            {{ title }}
            {{ permalink }}
            {{ permalink }}
            {{ date format="D, d M Y H:i:s O" }}
            {{ categories }}{{ title }}{{ /categories }}
            {{ if dek }}{{ dek }}{{ /if }}

    {{ /collection:articles }}
{{ /if }}
